// ─────────────────────────────────────────────
// VHSYS :: regular_bills  —  POST /regular_bills
// ─────────────────────────────────────────────
// A extensão envia allBills como ARRAY DIRETO: [{...}, ...]
// O Router encapsula em .body; testes diretos podem chegar sem .body
// ─────────────────────────────────────────────

const input = $input.first().json;
const body = (input.body !== undefined) ? input.body : input;

if (!Array.isArray(body)) {
  return { _valid: false, statusCode: 400, body: { ok: false, error: 'Expected array of regular bills' } };
}
if (body.length === 0) {
  return { _valid: false, statusCode: 400, body: { ok: false, error: 'Empty array provided' } };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'input_validated',
  items_count: body.length,
  level: 'info'
}));

return { _valid: true, items: body };

// ─────────────────────────────────────────────
// Decode HTML entities + Transform
// Espelha: decode_html_entities() + verify_elements()
// ─────────────────────────────────────────────
// PK     : id_custo (Text)
// Datas  : 'YYYY-MM-DD' (10) → + ' 00:00:00' | 'YYYY-MM-DD HH:MM:SS' (19)
// ATENÇÃO: created_at e updated_at COMENTADOS no model — não existem na tabela
// ─────────────────────────────────────────────

const ctx = $input.first().json;
const items = ctx.items;

function decodeHtml(obj) {
  if (typeof obj === 'string') {
    return obj
      .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&#x27;/g, "'")
      .replace(/&#x2F;/g, '/').replace(/&nbsp;/g, ' ');
  }
  if (Array.isArray(obj)) return obj.map(decodeHtml);
  if (typeof obj === 'object' && obj !== null) {
    const out = {};
    for (const k in obj) out[k] = decodeHtml(obj[k]);
    return out;
  }
  return obj;
}

function transformToDatetime(val) {
  if (val === null || val === undefined || val === '') return null;
  const s = String(val).trim();
  if (s.length === 10) return s + ' 00:00:00';
  if (s.length === 19) return s;
  return s;
}

// Sanitiza string para SQL — retorna '' se null/undefined
// ESCAPE $ para evitar problemas com expressões n8n
function safe(val) {
  if (val === null || val === undefined) return '';
  return String(val).replace(/\$/g, '$ ');
}

const decodedItems = decodeHtml(items);
const result = [];

for (let i = 0; i < decodedItems.length; i++) {
  const reg = decodedItems[i];

  const id_custo = reg.id_custo !== undefined ? String(reg.id_custo).trim() : null;
  if (!id_custo) {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'regular_bills',
      event: 'item_skipped_missing_id_custo',
      item_index: i,
      level: 'warn'
    }));
    continue;
  }

  // id_empresa e nome_conta são NOT NULL no model — garantir string não vazia
  const id_empresa = String(reg.id_empresa ?? '').trim() || 'N/D';
  const nome_conta = String(reg.nome_conta ?? '').trim() || 'N/D';

  result.push({
    json: {
      id_custo,
      id_empresa,
      nome_conta,
      id_categoria:              String(reg.id_categoria ?? ''),
      categoria_custo:           safe(reg.categoria_custo),
      id_banco:                  String(reg.id_banco ?? ''),
      id_fornecedor:             String(reg.id_fornecedor ?? ''),
      nome_fornecedor:           safe(reg.nome_fornecedor),
      vencimento_custo:          String(reg.vencimento_custo ?? ''),
      valor_custo:               String(reg.valor_custo ?? ''),
      observacoes_custo:         safe(reg.observacoes_custo),
      id_centro_custos:          String(reg.id_centro_custos ?? ''),
      status_custo:              safe(reg.status_custo),
      forma_pagamento:           safe(reg.forma_pagamento),
      periodicidade:             String(reg.periodicidade ?? ''),
      dia_semana_ocorrencia:     String(reg.dia_semana_ocorrencia ?? ''),
      dia_mes_ocorrencia:        String(reg.dia_mes_ocorrencia ?? ''),
      intervalo_dias_ocorrencia: reg.intervalo_dias_ocorrencia ?? null,
      data_inicio_ocorrencia:    transformToDatetime(reg.data_inicio_ocorrencia),
      data_fim_ocorrencia:       transformToDatetime(reg.data_fim_ocorrencia),
      data_cad_custo:            transformToDatetime(reg.data_cad_custo),
      // lixeira é db.Column(db.String(16)) — pode vir null da API
      lixeira:                   reg.lixeira ?? null
    }
  });
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'items_transformed',
  valid_items: result.length,
  total_input: decodedItems.length,
  level: 'info'
}));

if (result.length === 0) {
  return [{ json: { _empty: true } }];
}

return result;

// Flask retorna: { 'message': 'GET A NEW regular_bills status ' } HTTP 201
const allRows = $input.all();
const upserted = allRows.filter(item => item.json && item.json.id_custo).length;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'upsert_complete',
  records_upserted: upserted,
  level: 'info'
}));

return { statusCode: 201, body: { message: 'GET A NEW regular_bills status ' } };

const errData = $input.first().json;
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));
return { statusCode: 500, body: { ok: false, error: 'Database error', message: 'Could not process regular bills' } };
